19	func TestRefHashMap(t *testing.T) {
20		hashA := plumbing.NewHash("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
21		hashB := plumbing.NewHash("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")
22	
23		refs := []*plumbing.Reference{
24			plumbing.NewHashReference("refs/heads/main", hashA),
25			plumbing.NewHashReference("refs/heads/dev", hashB),
26			plumbing.NewSymbolicReference("HEAD", "refs/heads/main"), // symbolic, should be skipped
27		}
28	
29		m := RefHashMap(refs)
30	
31		if len(m) != 2 {
32			t.Fatalf("expected 2 entries, got %d", len(m))
33		}
34		if got := m["refs/heads/main"]; got != hashA {
35			t.Errorf("refs/heads/main = %s, want %s", got, hashA)
36		}
37		if got := m["refs/heads/dev"]; got != hashB {
38			t.Errorf("refs/heads/dev = %s, want %s", got, hashB)
39		}
40	
41		// Empty input.
42		m = RefHashMap(nil)
43		if len(m) != 0 {
44			t.Errorf("RefHashMap(nil) returned %d entries, want 0", len(m))
45		}
46	}
