48	func TestHeadTargetFromAdv(t *testing.T) {
49		// nil returns empty.
50		if got := headTargetFromAdv(nil); got != "" {
51			t.Errorf("headTargetFromAdv(nil) = %q, want empty", got)
52		}
53	
54		adv := packp.NewAdvRefs()
55		if err := adv.Capabilities.Add(capability.SymRef, "HEAD:refs/heads/main"); err != nil {
56			t.Fatalf("Capabilities.Add: %v", err)
57		}
58		if got := headTargetFromAdv(adv); got.String() != "refs/heads/main" {
59			t.Errorf("headTargetFromAdv = %q, want refs/heads/main", got)
60		}
61	
62		// Symref pointing at something other than HEAD is ignored.
63		adv = packp.NewAdvRefs()
64		if err := adv.Capabilities.Add(capability.SymRef, "refs/remotes/origin/HEAD:refs/heads/main"); err != nil {
65			t.Fatalf("Capabilities.Add: %v", err)
66		}
67		if got := headTargetFromAdv(adv); got != "" {
68			t.Errorf("headTargetFromAdv ignored non-HEAD symref = %q, want empty", got)
69		}
