72	func TestAdvRefsCaps(t *testing.T) {
73		// nil AdvRefs should return nil.
74		if got := AdvRefsCaps(nil); got != nil {
75			t.Errorf("AdvRefsCaps(nil) = %v, want nil", got)
76		}
77	
78		// AdvRefs with nil Capabilities should return nil.
79		adv := &packp.AdvRefs{}
80		adv.Capabilities = nil
81		if got := AdvRefsCaps(adv); got != nil {
82			t.Errorf("AdvRefsCaps(nil caps) = %v, want nil", got)
83		}
84	
85		// AdvRefs with populated capabilities.
86		adv = packp.NewAdvRefs()
87		require.NoError(t, adv.Capabilities.Set(capability.OFSDelta))
88		require.NoError(t, adv.Capabilities.Add(capability.Agent, "git/test-agent"))
89		require.NoError(t, adv.Capabilities.Set(capability.NoProgress))
90	
91		items := AdvRefsCaps(adv)
92		if len(items) == 0 {
93			t.Fatal("expected non-empty capability list")
94		}
95	
96		// Verify that known capabilities appear in the output.
97		found := make(map[string]bool)
98		for _, item := range items {
99			found[item] = true
100		}
