102			t.Error("expected ofs-delta in capability list")
103		}
104		if !found["agent=git/test-agent"] {
105			t.Errorf("expected agent=git/test-agent in capability list, got items: %v", items)
106		}
107		if !found["no-progress"] {
108			t.Error("expected no-progress in capability list")
109		}
