	adv, refs, err := listSourceRefsV1(ctx, conn)
	if err != nil {
		return nil, nil, err
	}
	return refs, &RefService{Protocol: "v1", V1Adv: adv, HeadTarget: headTargetFromAdv(adv)}, nil
}

