	if len(data) == 0 {
		return ""
	}
	limit := 200
	if len(data) < limit {
		limit = len(data)
	}
	preview := string(data[:limit])
	preview = strings.ReplaceAll(preview, "\n", `\n`)
	preview = strings.ReplaceAll(preview, "\r", `\r`)
	if len(data) > limit {
