// NewSSHConn creates a new SSH transport connection backed by the local ssh
// binary.
func NewSSHConn(ep *url.URL, label string) (*SSHConn, error) {
	sshPath, err := SSHLookPath("ssh")
	if err != nil {
		return nil, fmt.Errorf("locate ssh binary: %w", err)
	}
	normalizeEndpointPath(ep)
	return &SSHConn{
		Label:       label,
		EndpointURL: ep,
		sshPath:     sshPath,
	}, nil
}

func (c *SSHConn) Endpoint() *url.URL { return c.EndpointURL }

func (c *SSHConn) ProgressWriter() io.Writer { return c.progressOut }

func (c *SSHConn) SetProgressWriter(w io.Writer) { c.progressOut = w }

func (c *SSHConn) Close() error { return nil }

func (c *SSHConn) RequestInfoRefs(ctx context.Context, service string, gitProtocol string) ([]byte, error) {
	cmd, stderr, err := c.startRPC(ctx, service, gitProtocol)
	if err != nil {
		return nil, err
	}
	return requestInfoRefsWithCommand(ctx, service, cmd, stderr)
}

func requestInfoRefsWithCommand(ctx context.Context, service string, cmd *sshCommand, stderr *sshCommandError) ([]byte, error) {
	if err := cmd.Stdin.Close(); err != nil {
		return nil, fmt.Errorf("close ssh stdin for %s: %w", service, errors.Join(err, cleanupSSHCommand(cmd)))
	}
	data, readErr := io.ReadAll(cmd.Stdout)
	waitErr := cmd.wait()
	if ctx.Err() != nil {
		return nil, errors.Join(ctx.Err(), readErr, stderr.wrap(waitErr))
	}
	if readErr != nil {
		return nil, fmt.Errorf("%s info-refs: %w", service, readErr)
	}
	if len(data) > 0 {
		return data, nil
	}
	if waitErr != nil {
		return nil, fmt.Errorf("%s info-refs: %w", service, stderr.wrap(waitErr))
	}
	return data, nil
}

func (c *SSHConn) PostRPCStreamBody(ctx context.Context, service string, body io.Reader, v2 bool, phase string) (io.ReadCloser, error) {
	_ = phase // phase labels are HTTP-only today; SSH transport has no per-RPC stats tagging
	gitProtocol := ""
	if v2 {
		gitProtocol = "version=2"
	}
	cmd, stderr, err := c.startRPC(ctx, service, gitProtocol)
	if err != nil {
		return nil, err
	}
	copyErr := make(chan error, 1)
	go func() {
		_, err := io.Copy(cmd.Stdin, body)
		closeErr := cmd.Stdin.Close()
		if err != nil {
			copyErr <- err
			return
		}
		copyErr <- closeErr
	}()
	stdout, err := discardSSHAdvertisement(cmd.Stdout)
	if err != nil {
		_ = cmd.Stdout.Close()
		waitErr := cmd.wait()
		return nil, fmt.Errorf("%s advertisement: %w", service, errors.Join(stderr.wrap(err), waitErr))
	}
	return &sshRPCStream{
		ctx:     ctx,
		stdout:  stdout,
		wait:    cmd.wait,
		copyErr: copyErr,
		stderr:  stderr,
	}, nil
}

func (c *SSHConn) startRPC(ctx context.Context, service string, gitProtocol string) (*sshCommand, *sshCommandError, error) {
	args, err := sshInvocationArgs(c.EndpointURL, service, gitProtocol)
	if err != nil {
		return nil, nil, err
	}
	cmd := exec.CommandContext(ctx, c.sshPath, args...)
	stderr := &sshCommandError{}
	cmd.Stderr = stderr
	stdout, err := cmd.StdoutPipe()
	if err != nil {
		return nil, nil, fmt.Errorf("open ssh stdout for %s: %w", service, err)
	}
	stdin, err := cmd.StdinPipe()
	if err != nil {
		return nil, nil, fmt.Errorf("open ssh stdin for %s: %w", service, err)
	}
	if err := cmd.Start(); err != nil {
		return nil, nil, fmt.Errorf("start ssh for %s: %w", service, stderr.wrap(err))
	}
	return &sshCommand{Cmd: cmd, Stdin: stdin, Stdout: stdout}, stderr, nil
}

func sshInvocationArgs(ep *url.URL, service string, gitProtocol string) ([]string, error) {
	destination, err := sshDestination(ep)
	if err != nil {
		return nil, err
	}
	remoteCommand, err := sshRemoteCommand(ep, service, gitProtocol)
	if err != nil {
		return nil, err
	}
	args := []string{"-o", "BatchMode=yes"}
	if port := ep.Port(); port != "" {
		args = append(args, "-p", port)
	}
	args = append(args, destination, remoteCommand)
	return args, nil
}

func sshDestination(ep *url.URL) (string, error) {
	if ep == nil || ep.Hostname() == "" {
		return "", errors.New("missing SSH host")
	}
	host := ep.Hostname()
	if ep.User != nil && ep.User.Username() != "" {
		return ep.User.Username() + "@" + host, nil
	}
	return host, nil
}

func sshRemoteCommand(ep *url.URL, service string, gitProtocol string) (string, error) {
	if ep == nil || ep.Path == "" {
		return "", errors.New("missing SSH repository path")
	}
	path := shellQuotePath(ep.Path)
	if gitProtocol != "" {
		return gitProtocolEnv(gitProtocol) + " " + service + " " + path, nil
	}
	return service + " " + path, nil
}

func gitProtocolEnv(gitProtocol string) string {
	return "GIT_PROTOCOL=" + shellQuote(gitProtocol)
}

func shellQuote(s string) string {
	return "'" + strings.ReplaceAll(s, "'", `'"'"'`) + "'"
}

func shellQuotePath(path string) string {
	if !strings.HasPrefix(path, "~") {
		return shellQuote(path)
	}
	slash := strings.IndexByte(path, '/')
	if slash < 0 {
		return path
	}
	return path[:slash+1] + shellQuote(path[slash+1:])
}

type sshCommand struct {
	Cmd    *exec.Cmd
	Stdin  io.WriteCloser
	Stdout io.ReadCloser
	waitFn func() error
}

func (c *sshCommand) wait() error {
	if c.waitFn != nil {
		return c.waitFn()
	}
	if err := c.Cmd.Wait(); err != nil {
		return fmt.Errorf("wait for ssh command: %w", err)
	}
	return nil
}

func cleanupSSHCommand(cmd *sshCommand) error {
	if cmd == nil {
		return nil
	}
	var errs []error
	if cmd.Stdout != nil {
		if err := cmd.Stdout.Close(); err != nil {
			errs = append(errs, fmt.Errorf("close ssh stdout: %w", err))
		}
	}
	if err := cmd.wait(); err != nil {
		errs = append(errs, err)
	}
	return errors.Join(errs...)
}

func discardSSHAdvertisement(stdout io.ReadCloser) (io.ReadCloser, error) {
	buffered := bufio.NewReader(stdout)
	header, err := buffered.Peek(4)
	if err != nil {
		if errors.Is(err, io.EOF) {
			return &bufferedReadCloser{Reader: buffered, Closer: stdout}, nil
		}
		return nil, fmt.Errorf("peek SSH advertisement: %w", err)
	}
	if !looksLikePktlineHeader(header) {
		return &bufferedReadCloser{Reader: buffered, Closer: stdout}, nil
	}
	reader := NewPacketReader(buffered)
	for {
		kind, _, err := reader.ReadPacket()
		if err != nil {
			return nil, err
		}
		if kind == PacketFlush {
			break
		}
	}
	return &bufferedReadCloser{Reader: reader.BufReader(), Closer: stdout}, nil
}

func looksLikePktlineHeader(header []byte) bool {
	if len(header) != 4 {
		return false
	}
	var fixed [4]byte
	copy(fixed[:], header)
	switch string(fixed[:]) {
	case "0000", "0001", "0002":
		return true
	}
	_, err := parseHexLength(fixed)
	return err == nil
}

type sshRPCStream struct {
	ctx     context.Context
	stdout  io.ReadCloser
	wait    func() error
	copyErr <-chan error
	stderr  *sshCommandError

	waitOnce sync.Once
	waitErr  error
}

type bufferedReadCloser struct {
	*bufio.Reader
	io.Closer
}

func (s *sshRPCStream) Read(p []byte) (int, error) {
	n, err := s.stdout.Read(p)
	return n, err //nolint:wrapcheck // io.Reader contract requires forwarding EOF and stream errors as-is
}

func (s *sshRPCStream) Close() error {
	closeErr := s.stdout.Close()
	s.waitOnce.Do(func() {
		copyErr := <-s.copyErr
		waitErr := s.wait()
		if copyErr != nil {
			s.waitErr = copyErr
			if waitErr != nil {
				s.waitErr = errors.Join(copyErr, s.stderr.wrap(waitErr))
			}
			return
		}
		if waitErr != nil {
			s.waitErr = s.stderr.wrap(waitErr)
		}
		if s.ctx != nil && s.ctx.Err() != nil {
			s.waitErr = errors.Join(s.ctx.Err(), s.waitErr)
		}
	})
	return errors.Join(closeErr, s.waitErr)
}

type sshCommandError struct {
	mu  sync.Mutex
	buf bytes.Buffer
}

func (e *sshCommandError) Write(p []byte) (int, error) {
	e.mu.Lock()
	defer e.mu.Unlock()
	return e.buf.Write(p) //nolint:wrapcheck // io.Writer implementation forwards buffer write errors verbatim
}

func (e *sshCommandError) String() string {
	e.mu.Lock()
	defer e.mu.Unlock()
	return strings.TrimSpace(e.buf.String())
}

func (e *sshCommandError) wrap(err error) error {
	if err == nil {
		return nil
	}
	if msg := e.String(); msg != "" {
		return fmt.Errorf("%w: %s", err, msg)
	}
	return err
}

package gitproto

import (
	"context"
	"errors"
	"io"
	"net/url"
	"strings"
	"testing"

	"github.com/go-git/go-git/v6/plumbing"
	"github.com/go-git/go-git/v6/plumbing/format/pktline"
	"github.com/go-git/go-git/v6/plumbing/protocol/packp"
	"github.com/go-git/go-git/v6/plumbing/protocol/packp/capability"
	"github.com/go-git/go-git/v6/plumbing/transport"
	"github.com/stretchr/testify/require"
)

func TestRefHashMap(t *testing.T) {
	hashA := plumbing.NewHash("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
	hashB := plumbing.NewHash("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")

	refs := []*plumbing.Reference{
		plumbing.NewHashReference(refsHeadsMain, hashA),
		plumbing.NewHashReference("refs/heads/dev", hashB),
		plumbing.NewSymbolicReference("HEAD", refsHeadsMain), // symbolic, should be skipped
	}

	m := RefHashMap(refs)

	if len(m) != 2 {
		t.Fatalf("expected 2 entries, got %d", len(m))
	}
	if got := m[refsHeadsMain]; got != hashA {
		t.Errorf("refs/heads/main = %s, want %s", got, hashA)
	}
	if got := m["refs/heads/dev"]; got != hashB {
		t.Errorf("refs/heads/dev = %s, want %s", got, hashB)
	}

	// Empty input.
	m = RefHashMap(nil)
	if len(m) != 0 {
		t.Errorf("RefHashMap(nil) returned %d entries, want 0", len(m))
	}
}

func TestHeadTargetFromAdv(t *testing.T) {
	// nil returns empty.
	if got := headTargetFromAdv(nil); got != "" {
		t.Errorf("headTargetFromAdv(nil) = %q, want empty", got)
	}

	adv := packp.NewAdvRefs()
	if err := adv.Capabilities.Add(capability.SymRef, "HEAD:refs/heads/main"); err != nil {
		t.Fatalf("Capabilities.Add: %v", err)
	}
	if got := headTargetFromAdv(adv); got.String() != refsHeadsMain {
		t.Errorf("headTargetFromAdv = %q, want refs/heads/main", got)
	}

	// Symref pointing at something other than HEAD is ignored.
	adv = packp.NewAdvRefs()
	if err := adv.Capabilities.Add(capability.SymRef, "refs/remotes/origin/HEAD:refs/heads/main"); err != nil {
		t.Fatalf("Capabilities.Add: %v", err)
	}
	if got := headTargetFromAdv(adv); got != "" {
		t.Errorf("headTargetFromAdv ignored non-HEAD symref = %q, want empty", got)
	}
}

func TestAdvRefsCaps(t *testing.T) {
	// nil AdvRefs should return nil.
	if got := AdvRefsCaps(nil); got != nil {
		t.Errorf("AdvRefsCaps(nil) = %v, want nil", got)
	}

	// AdvRefs with nil Capabilities should return nil.
	adv := &packp.AdvRefs{}
	adv.Capabilities = nil
	if got := AdvRefsCaps(adv); got != nil {
		t.Errorf("AdvRefsCaps(nil caps) = %v, want nil", got)
	}

	// AdvRefs with populated capabilities.
	adv = packp.NewAdvRefs()
	require.NoError(t, adv.Capabilities.Set(capability.OFSDelta))
	require.NoError(t, adv.Capabilities.Add(capability.Agent, "git/test-agent"))
	require.NoError(t, adv.Capabilities.Set(capability.NoProgress))

	items := AdvRefsCaps(adv)
	if len(items) == 0 {
		t.Fatal("expected non-empty capability list")
	}

	// Verify that known capabilities appear in the output.
	found := make(map[string]bool)
	for _, item := range items {
		found[item] = true
	}
	if !found["ofs-delta"] {
		t.Error("expected ofs-delta in capability list")
	}
	if !found["agent=git/test-agent"] {
		t.Errorf("expected agent=git/test-agent in capability list, got items: %v", items)
	}
	if !found["no-progress"] {
		t.Error("expected no-progress in capability list")
	}
}

func TestAdvRefsToSlice(t *testing.T) {
	adv := packp.NewAdvRefs()
	hashA := plumbing.NewHash("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
	hashB := plumbing.NewHash("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")
	adv.References = map[string]plumbing.Hash{
		refsHeadsMain:    hashA,
		"refs/heads/dev": hashB,
	}

	refs, err := AdvRefsToSlice(adv)
	if err != nil {
		t.Fatalf("AdvRefsToSlice: %v", err)
	}
	if len(refs) != 2 {
		t.Fatalf("expected 2 refs, got %d", len(refs))
	}

	found := make(map[plumbing.ReferenceName]plumbing.Hash)
	for _, ref := range refs {
		found[ref.Name()] = ref.Hash()
	}
	if found[refsHeadsMain] != hashA {
		t.Errorf("refs/heads/main = %s, want %s", found[refsHeadsMain], hashA)
	}
	if found["refs/heads/dev"] != hashB {
		t.Errorf("refs/heads/dev = %s, want %s", found["refs/heads/dev"], hashB)
	}
}

func TestDecodeV1AdvRefs(t *testing.T) {
	// Empty data should return ErrEmptyRemoteRepository.
	_, err := decodeV1AdvRefs(nil)
	if err == nil {
		t.Fatal("expected error for nil data, got nil")
	}

	// Empty bytes should also error.
	_, err = decodeV1AdvRefs([]byte{})
	if err == nil {
		t.Fatal("expected error for empty data, got nil")
	}
}

func TestDecodeV1AdvRefsSmartEmptyAdvertisement(t *testing.T) {
	var body strings.Builder
	if _, err := pktline.Writef(&body, "# service=%s\n", transport.ReceivePackService); err != nil {
		t.Fatalf("write smart service line: %v", err)
	}
	if err := pktline.WriteFlush(&body); err != nil {
		t.Fatalf("write smart flush: %v", err)
	}

	_, err := decodeV1AdvRefs([]byte(body.String()))
	if !errors.Is(err, transport.ErrEmptyRemoteRepository) {
		t.Fatalf("expected empty remote repository, got %v", err)
	}
}

func TestDecodeV1AdvRefsMalformedIncludesPreview(t *testing.T) {
	_, err := decodeV1AdvRefs([]byte("# service=git-receive-pack"))
	if err == nil {
		t.Fatal("expected malformed decode error")
	}
	if !strings.Contains(err.Error(), `body-prefix="# service=git-receive-pack"`) {
		t.Fatalf("expected body preview in error, got %v", err)
	}
}

func TestListSourceRefsUnsupportedProtocol(t *testing.T) {
	_, _, err := ListSourceRefs(context.Background(), nil, "v99", nil)
	if err == nil {
		t.Fatal("expected error for unsupported protocol mode")
	}
}

func TestListSourceRefsAutoFallsBackToV1AfterSSHV2ProbeError(t *testing.T) {
	t.Parallel()

	conn := &stubConn{
		reqInfoRefs: func(_ context.Context, _ string, gitProtocol string) ([]byte, error) {
			if gitProtocol == "version=2" {
				return nil, errors.New("ssh server rejected v2 probe")
			}

			var body strings.Builder
			if _, err := pktline.Writef(&body, "# service=%s\n", transport.UploadPackService); err != nil {
				t.Fatalf("write smart service line: %v", err)
			}
			if err := pktline.WriteFlush(&body); err != nil {
				t.Fatalf("write smart flush: %v", err)
			}
			if _, err := pktline.Writef(&body, "%s HEAD\x00%s\n", strings.Repeat("a", 40), capability.SymRef+"=HEAD:refs/heads/main"); err != nil {
				t.Fatalf("write advertised head: %v", err)
			}
			if _, err := pktline.Writef(&body, "%s refs/heads/main\n", strings.Repeat("a", 40)); err != nil {
				t.Fatalf("write advertised ref: %v", err)
			}
			if err := pktline.WriteFlush(&body); err != nil {
				t.Fatalf("write trailing flush: %v", err)
			}
			return []byte(body.String()), nil
		},
	}

	refs, svc, err := ListSourceRefs(t.Context(), conn, "auto", nil)
	if err != nil {
		t.Fatalf("ListSourceRefs(auto) error = %v", err)
	}
	if svc.Protocol != "v1" {
		t.Fatalf("protocol = %q, want v1", svc.Protocol)
	}
	if got := svc.HeadTarget.String(); got != refsHeadsMain {
		t.Fatalf("head target = %q, want refs/heads/main", got)
	}
	foundMain := false
	for _, ref := range refs {
		if ref.Name().String() == refsHeadsMain {
			foundMain = true
			break
		}
	}
	if !foundMain {
		t.Fatalf("refs = %#v, want refs/heads/main to be advertised", refs)
	}
}

func TestListSourceRefsAutoJoinsErrorsWhenV1FallbackAlsoFails(t *testing.T) {
	t.Parallel()

	v2Err := errors.New("ssh v2 probe failed")
	v1Err := errors.New("ssh v1 fallback failed")
	conn := &stubConn{
		reqInfoRefs: func(_ context.Context, _ string, gitProtocol string) ([]byte, error) {
			if gitProtocol == "version=2" {
				return nil, v2Err
			}
			return nil, v1Err
		},
	}

	_, _, err := ListSourceRefs(t.Context(), conn, "auto", nil)
	if err == nil {
		t.Fatal("expected error when both v2 probe and v1 fallback fail")
	}
	if !errors.Is(err, v2Err) {
		t.Errorf("err does not wrap v2 error: %v", err)
	}
	if !errors.Is(err, v1Err) {
		t.Errorf("err does not wrap v1 error: %v", err)
	}
}

func TestListSourceRefsAutoDoesNotFallBackForNonSSH(t *testing.T) {
	t.Parallel()

	v2Err := errors.New("https v2 probe failed")
	v1Called := false
	conn := &stubConn{
		reqInfoRefs: func(_ context.Context, _ string, gitProtocol string) ([]byte, error) {
			if gitProtocol == "version=2" {
				return nil, v2Err
			}
			v1Called = true
			return nil, errors.New("unexpected v1 call")
		},
		endpoint: &url.URL{Scheme: "https", Host: "github.com"},
	}

	_, _, err := ListSourceRefs(t.Context(), conn, "auto", nil)
	if err == nil {
		t.Fatal("expected error from v2 probe")
	}
	if !errors.Is(err, v2Err) {
		t.Errorf("err does not wrap v2 error: %v", err)
	}
	if v1Called {
		t.Error("v1 fallback should not be attempted for non-SSH schemes")
	}
}

type stubConn struct {
	reqInfoRefs func(ctx context.Context, service string, gitProtocol string) ([]byte, error)
	endpoint    *url.URL
}

func (s *stubConn) RequestInfoRefs(ctx context.Context, service string, gitProtocol string) ([]byte, error) {
	return s.reqInfoRefs(ctx, service, gitProtocol)
}

func (s *stubConn) PostRPCStreamBody(context.Context, string, io.Reader, bool, string) (io.ReadCloser, error) {
	return nil, errors.New("unexpected PostRPCStreamBody call")
}

func (s *stubConn) Endpoint() *url.URL {
	if s.endpoint != nil {
		return s.endpoint
	}
	return &url.URL{Scheme: "ssh", Host: "github.com"}
}

func (s *stubConn) ProgressWriter() io.Writer { return nil }

func (s *stubConn) SetProgressWriter(io.Writer) {}

func (s *stubConn) Close() error { return nil }

